-- Seed: real Shopee affiliate products
-- Wipes the legacy public.products table (and all dependent rows via CASCADE)
-- and replaces with 100 real Shopee products imported from the
-- partner CSV (Shopee Affiliate Marketing Solution).
--
-- Safe to run more than once: TRUNCATE CASCADE clears the table every time,
-- then the same INSERT batch is re-applied.

begin;

truncate table public.products restart identity cascade;


commit;
